INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('bangun-tidur', 1, 'Doa Bangun Tidur', 'الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ', 'Alhamdulillahilladzii ahyaanaa ba''da maa amaatanaa wa ilaihin-nusyuur', 'Segala puji bagi Allah yang telah menghidupkan kami setelah mematikan kami, dan kepada-Nya kami dibangkitkan.', 'Dibaca begitu terbangun dari tidur.', NULL, 'HR. Bukhari 6312, Muslim 2711');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('bangun-tidur', 2, 'Doa Mimpi Buruk', 'أَعُوذُ بِاللَّهِ مِنَ الشَّيْطَانِ الرَّجِيمِ', 'A''uudzu billaahi minasy-syaithaanir-rajiim', 'Aku berlindung kepada Allah dari setan yang terkutuk.', 'Bila bermimpi buruk: berlindung kepada Allah, meludah kecil ke kiri 3x, berpindah posisi, dan jangan menceritakannya.', NULL, 'HR. Muslim 2261');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('kamar-mandi', 1, 'Doa Masuk Kamar Mandi', 'بِسْمِ اللَّهِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْخُبُثِ وَالْخَبَائِثِ', 'Bismillaah, Allaahumma innii a''uudzu bika minal-khubutsi wal-khabaa-its', 'Dengan nama Allah. Ya Allah, aku berlindung kepada-Mu dari setan laki-laki dan setan perempuan.', 'Dibaca sebelum masuk, dahulukan kaki kiri.', NULL, 'HR. Bukhari 142, Muslim 375');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('kamar-mandi', 2, 'Doa Keluar Kamar Mandi', 'غُفْرَانَكَ', 'Ghufraanak', '(Aku memohon) ampunan-Mu.', 'Dibaca setelah keluar, dahulukan kaki kanan.', NULL, 'HR. Abu Dawud 30, Tirmidzi 7 (sahih)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('wudhu', 1, 'Sebelum Wudhu', 'بِسْمِ اللَّهِ', 'Bismillaah', 'Dengan nama Allah.', 'Membaca basmalah di awal wudhu.', NULL, 'HR. Abu Dawud 101 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('wudhu', 2, 'Sesudah Wudhu', 'أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ', 'Asyhadu an laa ilaaha illallaahu wahdahu laa syariika lah, wa asyhadu anna Muhammadan ''abduhu wa rasuuluh', 'Aku bersaksi tiada Tuhan selain Allah semata, tiada sekutu bagi-Nya, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya.', 'Siapa membacanya, dibukakan baginya delapan pintu surga.', NULL, 'HR. Muslim 234');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('pakaian', 1, 'Doa Memakai Pakaian', 'الْحَمْدُ لِلَّهِ الَّذِي كَسَانِي هَذَا الثَّوْبَ وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ', 'Alhamdulillahilladzii kasaanii haadzats-tsauba wa razaqaniihi min ghairi haulin minnii wa laa quwwah', 'Segala puji bagi Allah yang telah memberiku pakaian ini dan menganugerahkannya kepadaku tanpa daya dan kekuatan dariku.', 'Diampuni dosanya yang telah lalu.', NULL, 'HR. Abu Dawud 4023, Tirmidzi 3458 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('pakaian', 2, 'Doa Memakai Pakaian Baru', 'اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ كَسَوْتَنِيهِ، أَسْأَلُكَ خَيْرَهُ وَخَيْرَ مَا صُنِعَ لَهُ، وَأَعُوذُ بِكَ مِنْ شَرِّهِ وَشَرِّ مَا صُنِعَ لَهُ', 'Allaahumma lakal-hamdu anta kasautaniih, as-aluka khairahu wa khaira maa shuni''a lah, wa a''uudzu bika min syarrihi wa syarri maa shuni''a lah', 'Ya Allah, bagi-Mu segala puji, Engkau yang memberiku pakaian ini. Aku memohon kebaikannya dan kebaikan tujuan pembuatannya, dan berlindung dari keburukannya dan keburukan tujuan pembuatannya.', 'Dibaca saat mengenakan pakaian baru.', NULL, 'HR. Abu Dawud 4020, Tirmidzi 1767 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('rumah', 1, 'Doa Keluar Rumah', 'بِسْمِ اللَّهِ تَوَكَّلْتُ عَلَى اللَّهِ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ', 'Bismillaah, tawakkaltu ''alallaah, wa laa haula wa laa quwwata illaa billaah', 'Dengan nama Allah, aku bertawakal kepada Allah, tiada daya dan kekuatan kecuali dengan Allah.', 'Dikatakan kepadanya: engkau diberi petunjuk, dicukupi, dan dijaga; setan pun menjauh.', NULL, 'HR. Abu Dawud 5095, Tirmidzi 3426 (sahih)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('rumah', 2, 'Doa Masuk Rumah', 'بِسْمِ اللَّهِ وَلَجْنَا، وَبِسْمِ اللَّهِ خَرَجْنَا، وَعَلَى اللَّهِ رَبِّنَا تَوَكَّلْنَا', 'Bismillaahi walajnaa, wa bismillaahi kharajnaa, wa ''alallaahi rabbinaa tawakkalnaa', 'Dengan nama Allah kami masuk, dengan nama Allah kami keluar, dan kepada Allah Tuhan kami, kami bertawakal.', 'Lalu mengucap salam kepada penghuni rumah.', NULL, 'HR. Abu Dawud 5096 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('masjid', 1, 'Doa Masuk Masjid', 'اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ', 'Allaahummaftah lii abwaaba rahmatik', 'Ya Allah, bukakanlah untukku pintu-pintu rahmat-Mu.', 'Masuk dengan mendahulukan kaki kanan.', NULL, 'HR. Muslim 713');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('masjid', 2, 'Doa Keluar Masjid', 'اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ', 'Allaahumma innii as-aluka min fadhlik', 'Ya Allah, sesungguhnya aku memohon karunia-Mu.', 'Keluar dengan mendahulukan kaki kiri.', NULL, 'HR. Muslim 713');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('makan', 1, 'Doa Sebelum Makan', 'بِسْمِ اللَّهِ', 'Bismillaah', 'Dengan nama Allah.', 'Jika lupa di awal, ucapkan: ''Bismillaahi awwalahu wa aakhirahu'' saat teringat.', NULL, 'HR. Abu Dawud 3767, Tirmidzi 1858 (sahih)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('makan', 2, 'Doa Sesudah Makan', 'الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنِي هَذَا وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ', 'Alhamdulillahilladzii ath''amanii haadzaa wa razaqaniihi min ghairi haulin minnii wa laa quwwah', 'Segala puji bagi Allah yang telah memberiku makan ini dan menganugerahkannya tanpa daya dan kekuatan dariku.', 'Diampuni dosanya yang telah lalu.', NULL, 'HR. Abu Dawud 4023, Tirmidzi 3458 (hasan)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('kendaraan', 1, 'Doa Naik Kendaraan', 'سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ وَإِنَّا إِلَى رَبِّنَا لَمُنْقَلِبُونَ', 'Subhaanalladzii sakhkhara lanaa haadzaa wa maa kunnaa lahu muqriniin, wa innaa ilaa rabbinaa lamunqalibuun', 'Mahasuci Allah yang telah menundukkan ini bagi kami, padahal kami tidak mampu menguasainya. Dan sesungguhnya kami akan kembali kepada Tuhan kami.', 'Diawali membaca ''Bismillaah'' lalu ''Alhamdulillah'' tiga kali dan takbir tiga kali.', NULL, 'QS. Az-Zukhruf 13-14; HR. Muslim 1342, Abu Dawud 2602');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('tidur', 1, 'Doa Sebelum Tidur', 'بِاسْمِكَ اللَّهُمَّ أَمُوتُ وَأَحْيَا', 'Bismika Allaahumma amuutu wa ahyaa', 'Dengan nama-Mu ya Allah, aku mati dan aku hidup.', 'Sunnah tidur dengan berwudhu dan berbaring ke sisi kanan.', NULL, 'HR. Bukhari 6324');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('tidur', 2, 'Membaca Ayat Kursi Sebelum Tidur', 'اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ ...', 'Allaahu laa ilaaha illaa huwal-hayyul-qayyuum ...', 'Membaca Ayat Kursi (QS. Al-Baqarah: 255) sebelum tidur.', 'Siapa membacanya sebelum tidur, Allah senantiasa menjaganya dan setan tidak mendekatinya hingga pagi.', NULL, 'HR. Bukhari 2311');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('tidur', 3, 'Tiga Qul Sebelum Tidur', 'قُلْ هُوَ اللَّهُ أَحَدٌ • قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ • قُلْ أَعُوذُ بِرَبِّ النَّاسِ', 'Qul huwallaahu ahad • Qul a''uudzu bi rabbil-falaq • Qul a''uudzu bi rabbin-naas', 'Membaca Al-Ikhlas, Al-Falaq, dan An-Nas, lalu ditiupkan ke kedua telapak tangan dan diusapkan ke seluruh tubuh, 3 kali.', 'Diamalkan Nabi ﷺ setiap malam sebelum tidur.', 3, 'HR. Bukhari 5017');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('dzikir-pagi-petang', 1, 'Sayyidul Istighfar', 'اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ، خَلَقْتَنِي وَأَنَا عَبْدُكَ، وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ، أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ، أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ وَأَبُوءُ بِذَنْبِي فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ', 'Allaahumma anta rabbii laa ilaaha illaa anta, khalaqtanii wa anaa ''abduk, wa anaa ''alaa ''ahdika wa wa''dika mastatha''tu, a''uudzu bika min syarri maa shana''tu, abuu-u laka bi ni''matika ''alayya wa abuu-u bi dzanbii faghfir lii fa innahu laa yaghfirudz-dzunuuba illaa anta', 'Ya Allah, Engkau Tuhanku, tiada Tuhan selain Engkau. Engkau menciptakanku dan aku hamba-Mu. Aku memegang janji-Mu sekuat kemampuanku. Aku berlindung dari keburukan perbuatanku. Aku mengakui nikmat-Mu dan dosaku, maka ampunilah aku, karena tiada yang mengampuni dosa kecuali Engkau.', 'Penghulu istighfar. Siapa membacanya di pagi hari dengan yakin lalu wafat hari itu, ia masuk surga; demikian pula di petang hari.', NULL, 'HR. Bukhari 6306');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('dzikir-pagi-petang', 2, 'Subhanallah wa bihamdih (100x)', 'سُبْحَانَ اللَّهِ وَبِحَمْدِهِ', 'Subhaanallaahi wa bihamdih', 'Mahasuci Allah dan segala puji bagi-Nya.', 'Siapa membacanya 100 kali dalam sehari, dihapus dosa-dosanya walau sebanyak buih di laut.', 100, 'HR. Bukhari 6405, Muslim 2691');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('dzikir-pagi-petang', 3, 'Perlindungan dengan Kalimat Allah (3x)', 'أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ مِنْ شَرِّ مَا خَلَقَ', 'A''uudzu bi kalimaatillaahit-taammaati min syarri maa khalaq', 'Aku berlindung dengan kalimat-kalimat Allah yang sempurna dari keburukan makhluk ciptaan-Nya.', 'Siapa membacanya 3x di petang hari, tidak akan dicelakai racun/binatang berbisa pada malam itu.', 3, 'HR. Muslim 2709');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('dzikir-setelah-shalat', 1, 'Istighfar (3x)', 'أَسْتَغْفِرُ اللَّهَ', 'Astaghfirullaah', 'Aku memohon ampun kepada Allah.', 'Dibaca 3 kali seusai salam.', 3, 'HR. Muslim 591');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('dzikir-setelah-shalat', 2, 'Tasbih, Tahmid, Takbir (33x)', 'سُبْحَانَ اللَّهِ • الْحَمْدُ لِلَّهِ • اللَّهُ أَكْبَرُ', 'Subhaanallaah (33x) • Alhamdulillah (33x) • Allaahu akbar (33x)', 'Mahasuci Allah • Segala puji bagi Allah • Allah Mahabesar. Digenapkan 100 dengan laa ilaaha illallaah...', 'Siapa membacanya seusai shalat, diampuni dosanya walau sebanyak buih di laut.', 33, 'HR. Muslim 597');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('thibb-nabawi', 1, 'Madu — Obat bagi Manusia', 'يَخْرُجُ مِنْ بُطُونِهَا شَرَابٌ مُخْتَلِفٌ أَلْوَانُهُ فِيهِ شِفَاءٌ لِلنَّاسِ', 'Yakhruju min buthuunihaa syaraabun mukhtalifun alwaanuhu fiihi syifaa-un lin-naas', 'Dari perut lebah itu keluar minuman (madu) yang bermacam-macam warnanya, di dalamnya terdapat obat bagi manusia.', 'Madu disebut langsung dalam Al-Qur''an sebagai obat. Nabi ﷺ menganjurkan madu untuk sakit perut.', NULL, 'QS. An-Nahl 68-69; HR. Bukhari 5684');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('thibb-nabawi', 2, 'Habbatussauda (Jintan Hitam)', 'فِي الْحَبَّةِ السَّوْدَاءِ شِفَاءٌ مِنْ كُلِّ دَاءٍ إِلَّا السَّامَ', 'Fil-habbatis-saudaa-i syifaa-un min kulli daa-in illas-saam', 'Pada habbatussauda terdapat obat bagi segala penyakit kecuali kematian.', 'As-saam artinya kematian. Dikonsumsi sebagai penguat daya tahan tubuh.', NULL, 'HR. Bukhari 5688, Muslim 2215');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('thibb-nabawi', 3, 'Bekam (Hijamah)', 'إِنَّ أَمْثَلَ مَا تَدَاوَيْتُمْ بِهِ الْحِجَامَةُ', 'Inna amtsala maa tadaawaitum bihil-hijaamah', 'Sesungguhnya pengobatan terbaik yang kalian gunakan adalah bekam.', 'Sunnah pengobatan mengeluarkan darah kotor. Waktu yang dianjurkan sebagian ulama: tanggal 17, 19, 21 Hijriah.', NULL, 'HR. Bukhari 5696, Muslim 1577');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('thibb-nabawi', 4, 'Kurma Ajwa', 'مَنْ تَصَبَّحَ كُلَّ يَوْمٍ سَبْعَ تَمَرَاتٍ عَجْوَةً لَمْ يَضُرَّهُ فِي ذَلِكَ الْيَوْمِ سُمٌّ وَلَا سِحْرٌ', 'Man tashabbaha kulla yaumin sab''a tamaraatin ''ajwatan lam yadhurrahu fii dzaalikal-yaumi summun wa laa sihr', 'Siapa mengonsumsi tujuh butir kurma Ajwa di pagi hari, ia tidak akan dicelakai racun maupun sihir pada hari itu.', 'Kurma Ajwa dari Madinah.', NULL, 'HR. Bukhari 5445, Muslim 2047');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('thibb-nabawi', 5, 'Air Zamzam', 'مَاءُ زَمْزَمَ لِمَا شُرِبَ لَهُ', 'Maa-u zamzama limaa syuriba lah', 'Air Zamzam (bermanfaat) sesuai niat saat diminum.', 'Diminum sambil berdoa memohon hajat; air yang penuh keberkahan.', NULL, 'HR. Ibnu Majah 3062 (hasan); Muslim 2473 (keberkahannya)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('ruqyah', 1, 'Ruqyah dengan Al-Fatihah', 'بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ ﴿الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ...﴾', 'Membaca Surah Al-Fatihah', 'Al-Fatihah dibaca lalu ditiupkan pada bagian yang sakit.', 'Al-Fatihah disebut ''Asy-Syifa'' (penyembuh). Para sahabat meruqyah dengannya atas izin Nabi ﷺ.', NULL, 'HR. Bukhari 5736, Muslim 2201');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('ruqyah', 2, 'Doa Menjenguk / Mengobati yang Sakit', 'أَذْهِبِ الْبَاسَ رَبَّ النَّاسِ، اشْفِ أَنْتَ الشَّافِي، لَا شِفَاءَ إِلَّا شِفَاؤُكَ، شِفَاءً لَا يُغَادِرُ سَقَمًا', 'Adzhibil-baasa rabban-naas, isyfi antasy-syaafii, laa syifaa-a illaa syifaa-uk, syifaa-an laa yughaadiru saqamaa', 'Hilangkanlah penyakit wahai Tuhan manusia, sembuhkanlah, Engkaulah Yang Maha Menyembuhkan, tiada kesembuhan kecuali kesembuhan dari-Mu, kesembuhan yang tidak menyisakan penyakit.', 'Diusapkan dengan tangan kanan pada yang sakit.', NULL, 'HR. Bukhari 5743, Muslim 2191');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('fitrah', 1, 'Lima Perkara Fitrah', 'الْفِطْرَةُ خَمْسٌ: الْخِتَانُ، وَالِاسْتِحْدَادُ، وَقَصُّ الشَّارِبِ، وَتَقْلِيمُ الْأَظْفَارِ، وَنَتْفُ الْإِبْطِ', 'Al-fithratu khams: al-khitaan, wal-istihdaad, wa qashsyusy-syaarib, wa taqliimul-azhfaar, wa natful-ibth', 'Fitrah itu ada lima: khitan, mencukur bulu kemaluan, memangkas kumis, memotong kuku, dan mencabut bulu ketiak.', 'Sunnah menjaga kebersihan dan kesucian diri; jangan dibiarkan lebih dari 40 hari.', NULL, 'HR. Bukhari 5891, Muslim 257');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('fitrah', 2, 'Bersiwak / Menyikat Gigi', 'لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ', 'Laulaa an asyuqqa ''alaa ummatii la-amartuhum bis-siwaaki ''inda kulli shalaah', 'Seandainya tidak memberatkan umatku, niscaya kuperintahkan mereka bersiwak setiap kali shalat.', 'Siwak menyucikan mulut dan diridhai Allah. Dianjurkan saat wudhu, shalat, bangun tidur, dan masuk rumah.', NULL, 'HR. Bukhari 887, Muslim 252');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('keindahan', 1, 'Allah Menyukai Keindahan', 'إِنَّ اللَّهَ جَمِيلٌ يُحِبُّ الْجَمَالَ', 'Innallaaha jamiilun yuhibbul-jamaal', 'Sesungguhnya Allah itu indah dan menyukai keindahan.', 'Berhias dan tampil rapi adalah bagian dari agama, selama tidak sombong dan tidak berlebihan.', NULL, 'HR. Muslim 91');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('keindahan', 2, 'Wewangian (Sunnah)', 'حُبِّبَ إِلَيَّ مِنْ دُنْيَاكُمُ النِّسَاءُ وَالطِّيبُ', 'Hubbiba ilayya min dunyaakumun-nisaa-u wath-thiib', 'Dijadikan aku menyukai dari dunia kalian: wanita (istri) dan wewangian.', 'Memakai wangi-wangian adalah sunnah, terutama saat Jumat dan hendak berkumpul. Bagi laki-laki: harum dan tidak berwarna mencolok.', NULL, 'HR. An-Nasa''i 3939 (hasan sahih)');
INSERT OR IGNORE INTO amalan_item (category_slug, item_order, title_id, arabic, latin, translation_id, note_id, repeat_count, source) VALUES ('keindahan', 3, 'Merawat & Memuliakan Rambut', 'مَنْ كَانَ لَهُ شَعْرٌ فَلْيُكْرِمْهُ', 'Man kaana lahu sya''run falyukrimhu', 'Siapa memiliki rambut, hendaklah ia memuliakannya (merawatnya).', 'Menyisir, meminyaki, dan menjaga kerapian rambut adalah sunnah.', NULL, 'HR. Abu Dawud 4163 (hasan)');
